import React from 'react';
import InputField from '../InputField';
import Buttons from '../Buttons';
import './screenthree.css';

const ScreenThree = ({ screen, nmscreen, formData, handleInputChange }) => {
  return (
    <div id="screen3" className="screen">
      <h1 className="title">Health and Other Conditions</h1>
      <div className="contact-details">
        <InputField
          className="health-problems"
          type="text"
          name="HealthProblems"
          value={formData.healthProblems}
          placeHolderMessage="Enter any health problems..."
          onChange={(e) => handleInputChange('healthProblems', e.target.value)}
        />
        <InputField
          className="other-conditions"
          type="text"
          name="OtherConditions"
          value={formData.otherConditions}
          placeHolderMessage="Enter other conditions..."
          onChange={(e) => handleInputChange('otherConditions', e.target.value)}
        />
      </div>
      <Buttons changeScreen={screen} back={"screen2"} next={"screen4"} nb={2} nn={4} />
    </div>
  );
};

export default ScreenThree;
